#include <bits/stdc++.h>
using namespace std;
const int maxn=1e2+5; 
int n,a[maxn],dp[maxn][maxn];
int sum(int i,int j){
	if(i==j){
		return a[j];
	}
	return abs(a[i]-a[j])*(j-i+1);
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	for(int i=1;i<=n;i++){
		for(int j=1;i+j-1<=n;j++){
			int s=i+j-1;
			dp[j][s]=sum(j,s);
			for(int k=j;k<s;k++){
				dp[j][s]=max(dp[j][s],dp[j][k]+dp[k+1][s]);
			}
		}
	}
	cout<<dp[1][n];
	return 0;
}
